import socket, threading, queue
q = queue.Queue()
for p in range(1, 100): q.put(p)

def worker():
    while not q.empty():
        port = q.get()
        s = socket.socket()
        s.settimeout(0.5)
        if s.connect_ex(('127.0.0.1', port)) == 0:
            print(f'Port {port} Open')
        s.close()
        q.task_done()

for i in range(10):
    threading.Thread(target=worker, daemon=True).start()
q.join()
